function CustomShopBlock:onEquipGoods(player, goods)
    local block = self.Settings[goods.SettingId]
    if not block then
        return
    end
    ---获取原来的装备的方块装扮
    local oldBlockId = player.equip_dress[tostring(block.BlockId)] or block.BlockId
    ---设置新的方块装扮
    player.equip_dress[tostring(block.BlockId)] = block.DressBlockId
    ---原来的装扮是羊毛原型(BlockId=35)，需要替换成队伍的羊毛方块Id
    if oldBlockId == BlockID.CLOTH then
        oldBlockId = player:getClothBlockId()
    end
    local blockItemId = BlockManager.getItemBlockId(oldBlockId)
    local inv = player:getInventory()
    for index = 0, 35 do
        local info = inv:getItemStackInfo(index)
        if info.id == blockItemId then
            inv:decrStackSize(index, info.num)
            player:tryAddItem(block.BlockId, info.num)
        end
    end
end

function CustomShopBlock:onUnloadGoods(player, goods)
    local block = self.Settings[goods.SettingId]
    if not block then
        return
    end
    local oldBlockId = block.BlockId
    if oldBlockId == BlockID.CLOTH then
        oldBlockId = player:getClothBlockId()
    end
    oldBlockId = player:tryItemId2DressId(oldBlockId)
    local blockItemId = BlockManager.getItemBlockId(oldBlockId)
    player.equip_dress[tostring(block.BlockId)] = nil
    local inv = player:getInventory()
    for index = 0, 35 do
        local info = inv:getItemStackInfo(index)
        if info.id == blockItemId then
            inv:decrStackSize(index, info.num)
            player:tryAddItem(block.BlockId, info.num)
        end
    end
end